var CAT_COLOR = {"관광아이디어발굴":"#2c6fbd","조직혁신":"#2a9d8f","사회적가치실현":"#b07800","기타":"#6b7280"};
var CAT_ICON  = {"관광아이디어발굴":"🗺️","조직혁신":"🔄","사회적가치실현":"🤝","기타":"📌"};
var CAT_CLASS = {"관광아이디어발굴":"b-관광아이디어발굴","조직혁신":"b-조직혁신","사회적가치실현":"b-사회적가치실현","기타":"b-기타"};
var AWARD_LABELS = ["심사중","최우수","우수","장려","특별상","미채택"];

function periodSort(p) {
  if (!p) return 0;
  var y = parseInt(p);
  if (p.includes('상반기')) return y*10+1;
  if (p.includes('하반기')) return y*10+2;
  return y*10;
}
function periodBadge(p) {
  if (!p) return '';
  var cls = p.includes('상반기') ? 'p-상반기' : p.includes('하반기') ? 'p-하반기' : 'p-연간';
  return '<span class="period-badge '+cls+'">'+p+'</span>';
}
function catBadge(c)  { return '<span class="badge '+(CAT_CLASS[c]||'b-기타')+'">'+c+'</span>'; }
function awardBadge(a){ return '<span class="abadge a-'+a+'"><span class="adot"></span>'+a+'</span>'; }
function esc(s)       { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// 로딩 오버레이
function showLoadingOverlay(msg) {
  var el = document.getElementById('loading-overlay');
  if (el) { el.style.display = 'flex'; }
  var txt = document.getElementById('loading-text');
  if (txt && msg) txt.textContent = msg;
}
