// ── PDF 미리보기 ─────────────────────────────────────
function fillFilename(fileInputId, textInputId) {
  var file = document.getElementById(fileInputId).files[0];
  if (!file) return;
  var fname = file.name;
  // 파일명 앞에 연도 폴더 자동 추가 (2017_01_... → 2017/2017_01_...)
  var yearMatch = fname.match(/^(\d{4})[_-]/);
  var storedName = yearMatch ? yearMatch[1] + '/' + fname : fname;
  document.getElementById(textInputId).value = storedName;

  var isForm = textInputId === 'f_pdf';
  var titleId  = isForm ? 'f_title'  : 'e_title';
  var periodId = isForm ? 'f_period' : 'e_period';

  // ── 연도 자동입력 ──────────────────────────────
  // 파일명 앞에서 연도 추출: 2017_... 또는 2024상반기_... 또는 2024하반기_...
  var periodEl = document.getElementById(periodId);
  if (periodEl) {
    var ymHalf = fname.match(/^(\d{4})(상반기|하반기)/);  // 2024상반기
    var ymYear = fname.match(/^(\d{4})_/);                // 2017_
    var detected = ymHalf ? ymHalf[1]+ymHalf[2] : (ymYear ? ymYear[1] : null);
    if (detected) {
      // select 옵션에 있으면 선택
      var opts = Array.from(periodEl.options).map(o => o.value);
      if (opts.includes(detected)) periodEl.value = detected;
    }
  }

  // ── 제목 자동입력 ──────────────────────────────
  var name = fname.replace(/\.[^.]+$/, '');               // 확장자 제거
  name = name.replace(/^\d{4}(상반기|하반기)?_\d+_/, ''); // 2024상반기_01_ 제거
  name = name.replace(/^\d{4}_\d+_/, '');                // 2017_01_ 제거
  name = name.replace(/^\d{4}(상반기|하반기)?_/, '');      // 2024상반기_ 제거
  name = name.replace(/_/g, ' ');                           // 언더바 → 띄어쓰기
  var titleEl = document.getElementById(titleId);
  if (titleEl && !titleEl.value.trim()) titleEl.value = name;
}
function previewPdf(inputId) {
  var fn=document.getElementById(inputId).value.trim();
  if (!fn) { showToast('파일명을 먼저 입력하세요','err'); return; }
  window.open(''+fn,'_blank');
}

// ── 통계 ─────────────────────────────────────────────
function renderStats() {
  var total=DATA.length, adopted=DATA.filter(d=>ADOPTED.has(d.award)).length,
      reviewing=DATA.filter(d=>d.award==='심사중').length, top=DATA.filter(d=>d.award==='최우수').length;
  var statsEl=document.getElementById('statsArea'); if(!statsEl)return;
  statsEl.innerHTML=[
    {cls:'sc1',vcls:'sv1',icon:'📝',val:total+'건',   label:'전체 제안'},
    {cls:'sc2',vcls:'sv2',icon:'🏆',val:adopted+'건', label:'채택 (수상)'},
    {cls:'sc3',vcls:'sv3',icon:'🔍',val:reviewing+'건',label:'심사 중'},
    {cls:'sc4',vcls:'sv4',icon:'⭐',val:top+'건',     label:'최우수 수상'},
  ].map(s=>'<div class="stat-card '+s.cls+'"><div class="stat-icon">'+s.icon+'</div>'
    +'<div><div class="stat-val '+s.vcls+'">'+s.val+'</div><div class="stat-label">'+s.label+'</div></div></div>'
  ).join('');
}

// ── 필터 ─────────────────────────────────────────────
function populateFilters() {
  var periods=[...new Set(DATA.map(d=>d.period))].sort((a,b)=>periodSort(b)-periodSort(a));
  var fp=document.getElementById('fPeriod'); if(!fp)return; var sp=fp.value;
  fp.innerHTML='<option value="">전체 기간</option>';
  periods.forEach(p=>fp.innerHTML+='<option'+(sp===p?' selected':'')+'>'+p+'</option>');
  var fa=document.getElementById('fAward'), sa=fa.value;
  fa.innerHTML='<option value="">전체 결과</option>';
  AWARD_LABELS.forEach(v=>fa.innerHTML+='<option'+(sa===v?' selected':'')+'>'+v+'</option>');
  var fc=document.getElementById('fCat'), sc=fc.value;
  fc.innerHTML='<option value="">전체 분류</option>';
  ['관광아이디어발굴','조직혁신','사회적가치실현','기타'].forEach(v=>
    fc.innerHTML+='<option'+(sc===v?' selected':'')+'>'+v+'</option>');
}

// ── 목록 ─────────────────────────────────────────────
var _checkedIds = new Set();

function toggleCheck(id, cb) {
  if (cb.checked) _checkedIds.add(id);
  else _checkedIds.delete(id);
  document.getElementById('bulkBar').style.display = _checkedIds.size > 0 ? 'flex' : 'none';
  document.getElementById('bulkCount').textContent = _checkedIds.size+'건 선택됨';
}
function bulkChangeAward(val) {
  if (!val) return;
  if (!_gToken) { showToast('🔑 Google 로그인 후 변경 가능합니다','err'); document.getElementById('bulkSel').value=''; return; }
  _checkedIds.forEach(id=>{
    var idx=DATA.findIndex(x=>String(x.id)===String(id)); if(idx===-1) return;
    DATA[idx].award=val;
    saveToSheet(DATA[idx]);
  });
  _checkedIds.clear();
  document.getElementById('bulkBar').style.display='none';
  document.getElementById('bulkSel').value='';
  showToast('일괄 변경 완료!','ok');
  renderAll();
}
function getFiltered() {
  var q=document.getElementById('srch').value.toLowerCase();
  var fc=document.getElementById('fCat').value, fa=document.getElementById('fAward').value, fp=document.getElementById('fPeriod').value;
  return DATA.filter(d=>{
    var mq=!q||d.title.toLowerCase().includes(q)
             ||(d.summary&&d.summary.toLowerCase().includes(q))
             ||(d.keywords&&d.keywords.toLowerCase().includes(q))
             ||(isAdmin&&((d.proposer&&d.proposer.toLowerCase().includes(q))||(d.dept&&d.dept.toLowerCase().includes(q))));
    return mq&&(!fc||d.category===fc)&&(!fa||d.award===fa)&&(!fp||d.period===fp);
  }).sort((a,b)=>{
    if(sortCol==='period') return (periodSort(b.period)-periodSort(a.period))*sortDir*-1;
    var av=a[sortCol]||'', bv=b[sortCol]||'';
    return av.localeCompare(bv)*sortDir;
  });
}
function renderTable() {
  _checkedIds.clear();
  document.getElementById('bulkBar').style.display='none';
  var list=getFiltered();
  document.getElementById('cntLbl').textContent=list.length+'건';
  var cols=[
    ...(isAdmin?[{key:'chk', label:'', w:'36px'}]:[]),
    {key:'id',     label:'번호',   w:'44px'},
    {key:'title',  label:'제목',   w:''},
    ...(isAdmin?[{key:'proposer',label:'제안자',w:'80px'},{key:'dept',label:'부서',w:'100px'}]:[]),
    {key:'category',label:'분류',  w:'130px'},
    {key:'award',  label:'심사결과',w:'120px'},
    {key:'period', label:'기간',   w:'110px'},
    {key:'pdf',    label:'PDF',    w:'50px'},
  ];
  document.getElementById('tblHead').innerHTML='<tr>'+cols.map(c=>{
    var arr=sortCol===c.key?(sortDir===1?' ▲':' ▼'):'';
    return '<th onclick="doSort(\''+c.key+'\')" style="width:'+c.w+'">'+c.label+arr+'</th>';
  }).join('')+'</tr>';
  if (!list.length) {
    var msg = DATA_LOADED ? '검색 결과가 없습니다.' : '자료를 불러오는 중입니다...';
    document.getElementById('tblBody').innerHTML='<tr><td colspan="'+cols.length+'" class="empty">'+msg+'</td></tr>';
    return;
  }
  document.getElementById('tblBody').innerHTML=list.map((d,i)=>{
    var catCell, awardCell;
    if (isAdmin) {
      var catOpts=['관광아이디어발굴','조직혁신','사회적가치실현','기타'].map(v=>'<option'+(d.category===v?' selected':'')+'>'+v+'</option>').join('');
      catCell='<td onclick="event.stopPropagation()"><select class="inline-sel" onchange="quickEdit(\''+d.id+'\',\'category\',this.value)">'+catOpts+'</select></td>';
      var awdOpts=AWARD_LABELS.map(v=>'<option'+(d.award===v?' selected':'')+'>'+v+'</option>').join('');
      awardCell='<td onclick="event.stopPropagation()"><select class="inline-sel" onchange="quickEdit(\''+d.id+'\',\'award\',this.value)">'+awdOpts+'</select></td>';
    } else {
      catCell='<td>'+catBadge(d.category)+'</td>';
      awardCell='<td>'+awardBadge(d.award)+'</td>';
    }
    var rowClick = isAdmin ? 'openEdit(\''+d.id+'\')' : '_fromTab=\'list\';openDetail(\''+d.id+'\')';
    return '<tr onclick="'+rowClick+'">'
      +(isAdmin?'<td onclick="event.stopPropagation()"><input type="checkbox" onchange="toggleCheck(\''+d.id+'\',this)"></td>':'')
      +'<td class="num">'+String(i+1).padStart(2,'0')+'</td>'
      +titleCell(d)
      +(isAdmin?'<td style="font-size:13px;color:#445">'+esc(d.proposer)+'</td><td style="font-size:12px;color:#667">'+esc(d.dept)+'</td>':'')
      +catCell+awardCell
      +'<td>'+periodBadge(d.period)+'</td>'
      +'<td style="text-align:center">'+(d.pdf?'<span title="'+esc(d.pdf)+'">📄</span>':'')+'</td>'
      +'</tr>';
  }).join('');
}
function doSort(col) { sortDir=(sortCol===col)?sortDir*-1:-1; sortCol=col; renderTable(); }

// ── 구글 OAuth ───────────────────────────────────────
var CLIENT_ID = '856327706288-p67pi593kvg70t83ecemg39lrcsdibqj.apps.googleusercontent.com';
var SCOPE = 'https://www.googleapis.com/auth/spreadsheets';
var _gToken = null;
var _tokenClient = null;

function initGoogleAuth() {
  if (!window.google) return;
  _tokenClient = google.accounts.oauth2.initTokenClient({
    client_id: CLIENT_ID,
    scope: SCOPE,
    callback: function(resp) {
      if (resp.error) { showToast('Google 로그인 실패: ' + resp.error, 'err'); return; }
      _gToken = resp.access_token;
      document.getElementById('googleBtn').textContent = '✅ Google';
      document.getElementById('googleBtn').style.background = '#e6f8f5';
      document.getElementById('googleBtn').style.color = '#2a9d8f';
      showToast('Google 연결됐습니다!', 'ok');
    }
  });
}
function googleLogin() {
  if (!_tokenClient) { showToast('Google 라이브러리 로딩 중...', 'err'); return; }
  if (_gToken) {
    _gToken = null;
    document.getElementById('googleBtn').textContent = '🔑 Google';
    document.getElementById('googleBtn').style.background = '#fff';
    document.getElementById('googleBtn').style.color = '#444';
    showToast('Google 연결 해제', 'ok');
    return;
  }
  _tokenClient.requestAccessToken();
}

// ── 구글 시트 쓰기 ───────────────────────────────────
function findRowBySeq(seq, callback) {
  // 시트에서 순번으로 행 번호 찾기
  fetch('https://sheets.googleapis.com/v4/spreadsheets/'+SHEET_ID+'/values/Sheet1!A:A', {
    headers: { Authorization: 'Bearer ' + _gToken }
  }).then(r=>r.json()).then(data=>{
    var rows = data.values || [];
    var rowIdx = rows.findIndex(r=>r[0]===seq);
    callback(rowIdx >= 0 ? rowIdx + 1 : -1); // 1-based
  }).catch(()=>callback(-1));
}

function deleteFromSheet(seq) {
  if (!_gToken || !seq) return;
  // Sheet1의 sheetId 먼저 조회
  fetch('https://sheets.googleapis.com/v4/spreadsheets/'+SHEET_ID+'?fields=sheets.properties', {
    headers: { Authorization: 'Bearer ' + _gToken }
  }).then(r=>r.json()).then(meta=>{
    var sheet1 = (meta.sheets||[]).find(s=>s.properties.title==='Sheet1');
    var sheetId = sheet1 ? sheet1.properties.sheetId : 0;
    findRowBySeq(seq, function(rowNum) {
      if (rowNum < 0) return;
      fetch('https://sheets.googleapis.com/v4/spreadsheets/'+SHEET_ID+':batchUpdate', {
        method: 'POST',
        headers: { Authorization: 'Bearer ' + _gToken, 'Content-Type': 'application/json' },
        body: JSON.stringify({ requests: [{ deleteDimension: { range: {
          sheetId: sheetId, dimension: 'ROWS', startIndex: rowNum-1, endIndex: rowNum
        }}}]})
      }).catch(()=>showToast('시트 삭제 실패','err'));
    });
  }).catch(()=>showToast('시트 삭제 실패','err'));
}

function saveToSheet(d, oldSeq) {
  if (!_gToken) return;
  if (!d.seq) return;
  var lookupSeq = oldSeq || d.seq;
  findRowBySeq(lookupSeq, function(rowNum) {
    if (rowNum < 0) { showToast('시트에서 행을 찾지 못했습니다', 'err'); return; }
    var values = [[d.seq, d.title, d.category, d.summary, d.keywords||'', d.proposer, d.dept, d.award, d.pdf||'']];
    fetch('https://sheets.googleapis.com/v4/spreadsheets/'+SHEET_ID+'/values/Sheet1!A'+rowNum+'?valueInputOption=RAW', {
      method: 'PUT',
      headers: { Authorization: 'Bearer ' + _gToken, 'Content-Type': 'application/json' },
      body: JSON.stringify({ values: values })
    }).then(r=>r.json()).then(()=>{
      showToast('시트에 저장됐습니다! ✅', 'ok');
    }).catch(()=>showToast('시트 저장 실패', 'err'));
  });
}

// ── 빠른 편집 ────────────────────────────────────────
function quickEdit(id, field, val) {
  if (!_gToken) { showToast('🔑 Google 로그인 후 수정 가능합니다','err'); return; }
  var idx=DATA.findIndex(x=>String(x.id)===String(id)); if(idx===-1) return;
  DATA[idx][field]=val;
  showToast('저장됐습니다!','ok');
  saveToSheet(DATA[idx]);
  if(_curId===id) openDetail(id);
}

// ── 상세 ─────────────────────────────────────────────
function getDetailList() {
  // 현재 필터 기준 목록 반환 (상세 이전/다음용)
  return getFiltered();
}
function openDetail(id) {
  var d=DATA.find(x=>String(x.id)===String(id)); if(!d) return;
  // 브라우저 히스토리에 상태 추가
  history.pushState({detail: id}, '', '#detail-'+id);
  _curId=id;
  // 현재 활성 탭 콘텐츠 숨기기
  document.querySelectorAll('.tab-content').forEach(el=>el.style.display='none');
  document.getElementById('listCard').style.display='none';
  document.getElementById('statsArea').style.display='none';
  document.getElementById('detailCard').style.display='block';
  document.getElementById('detailAward').innerHTML=awardBadge(d.award);
  document.getElementById('editBtn').style.display=isAdmin?'inline-block':'none';
  var cc=CAT_COLOR[d.category]||'#888';
  var adminMeta=isAdmin
    ?'<span class="admin-tag">'+esc(d.dept)+' · '+esc(d.proposer)+'</span>'
    :'<span class="lock-tag">🔒 제안자 정보는 관리자 공개</span>';
  var award = (d.award||'').trim();
  var steps=AWARD_LABELS.map(s=>'<span class="af-step '+(award===s?'abadge a-'+s:'')+'">'+ s+'</span>').join('');
  var pdfHtml='';
  if (d.pdf) {
    var fn=d.pdf, ext=fn.split('.').pop().toLowerCase();
    var isImg=['png','jpg','jpeg','gif','webp'].includes(ext);
    var icon=isImg?'🖼️':'📄';
    var viewer=isImg
      ?'<div style="border-radius:10px;overflow:hidden;border:1.5px solid #dde5f0;background:#fff;padding:16px;text-align:center">'
        +'<img src="'+esc(fn)+'" style="max-width:100%;border-radius:8px;box-shadow:0 2px 12px rgba(0,0,0,.1)" '
        +'onerror="this.style.display=&quot;none&quot;;this.nextElementSibling.style.display=&quot;block&quot;">'
        +'<div style="display:none;padding:20px;color:#aaa;font-size:13px">이미지를 불러올 수 없습니다.</div></div>'
      :'<div class="pdf-frame-wrap">'
        +'<iframe src="'+esc(fn)+'"></iframe>'
        +'<div class="pdf-fallback">PDF를 불러올 수 없습니다. <b>새 탭에서 열기</b>를 클릭하세요.</div></div>';
    pdfHtml='<div class="pdf-box">'
      +'<div class="dbox-lbl">📎 첨부 파일</div>'
      +'<div class="pdf-meta"><span class="pdf-name">'+icon+' '+esc(fn)+'</span>'
      +'<div class="pdf-btns">'
      +'<a class="pdf-btn-open" href="'+esc(fn)+'" target="_blank">🔍 새 탭에서 열기</a>'
      +'<a class="pdf-btn-dl" href="'+esc(fn)+'" download>⬇️ 다운로드</a>'
      +'</div></div>'+viewer+'</div>';
  } else {
    pdfHtml='<div class="dbox" style="margin-bottom:14px"><div class="dbox-lbl">📎 첨부 파일</div><div class="dbox-txt" style="color:#bbb">첨부 파일 없음</div></div>';
  }
  // 이전/다음 버튼 - 현재 탭 기준 목록
  var list;
  if (_fromTab === 'year') list = DATA.filter(d=>parseInt(d.period)===parseInt(_curYear||'0')).sort((a,b)=>periodSort(b.period)-periodSort(a.period));
  else if (_fromTab === 'cat') list = DATA.filter(d=>d.category===(_curCat||''));
  else if (_fromTab === 'adopted') list = DATA.filter(d=>ADOPTED.has(d.award));
  else list = getFiltered();
  var idx=list.findIndex(x=>String(x.id)===String(id));
  var prev=list[idx-1], next=list[idx+1];
  var navHtml='<div class="detail-nav">'
    +'<button class="det-nav-btn" '+(prev?'onclick="openDetailFrom(\''+prev.id+'\',\''+_fromTab+'\')"':'disabled')+'>'
    +'◀ <span class="det-nav-title">'+(prev?esc(prev.title):'처음입니다')+'</span></button>'
    +'<span class="det-nav-pos">'+(idx+1)+' / '+list.length+'</span>'
    +'<button class="det-nav-btn" '+(next?'onclick="openDetailFrom(\''+next.id+'\',\''+_fromTab+'\')"':'disabled')+'>'
    +'<span class="det-nav-title">'+(next?esc(next.title):'마지막입니다')+'</span> ▶</button>'
    +'</div>';
  document.getElementById('detailBody').innerHTML=
    '<div class="detail-top">'
    +'<div class="detail-cat-ico" style="background:'+cc+'1a">'+( CAT_ICON[d.category]||'💡')+'</div>'
    +'<div><div class="dtitle">'+esc(d.title)+'</div>'
    +'<div class="dmeta">'+catBadge(d.category)+' '+periodBadge(d.period)+' '+adminMeta+'</div></div>'
    +'</div>'
    +'<div class="dbox" style="margin-bottom:14px"><div class="dbox-lbl">💬 요약</div><div class="dbox-txt summary-lines">'+fmtSummary(d.summary||'요약 없음')+'</div>'+(d.keywords?'<div style="margin-top:10px">'+fmtKeywords(d.keywords)+'</div>':'')+'</div>'
    +pdfHtml
    +''
    +navHtml;
}
function openDetailFrom(id, fromTab) {
  _fromTab = fromTab || 'list';
  openDetail(id);
}

function closeDetail() {
  document.getElementById('detailCard').style.display='none';
  document.querySelectorAll('.tab-content').forEach(el=>el.style.display='');
  _curId=null;
  var tabIdx = {list:0, year:1, cat:2, adopted:3};
  var tabName = _fromTab || 'list';
  document.querySelectorAll('.tab-content').forEach(el=>el.classList.remove('on'));
  document.getElementById('tab-'+tabName).classList.add('on');
  document.querySelectorAll('.nav-btn').forEach((b,i)=>b.classList.toggle('on', i===tabIdx[tabName]));
  if (tabName==='list') {
    document.getElementById('listCard').style.display='block';
    document.getElementById('statsArea').style.display='none';
  }
}

// 브라우저 뒤로가기/앞으로가기 처리
window.addEventListener('popstate', function(e) {
  if (e.state && e.state.detail) {
    openDetail(e.state.detail);
  } else {
    closeDetail();
  }
});

// ── 연도별 ───────────────────────────────────────────
var _curYear = null;
function renderYear() {
  var periods=[...new Set(DATA.map(d=>d.period))].sort((a,b)=>periodSort(b)-periodSort(a));
  if (!periods.length) { document.getElementById('yearArea').innerHTML='<div class="card"><div class="empty">등록된 제안이 없습니다.</div></div>'; return; }
  var yearGroups={};
  periods.forEach(p=>{ var y=parseInt(p); if(!yearGroups[y]) yearGroups[y]=[]; yearGroups[y].push(p); });
  var years=Object.keys(yearGroups).sort((a,b)=>b-a);
  if (!_curYear || !yearGroups[_curYear]) _curYear=years[0];
  // 서브 탭 버튼
  document.getElementById('yearNav').innerHTML=years.map(yr=>
    '<button class="sub-nav-btn'+(yr==_curYear?' on':'')+'" onclick="selectYear('+yr+')">📅 '+yr+'년</button>'
  ).join('');
  showYearPanel(_curYear, yearGroups);
}
function selectYear(yr) {
  _curYear=yr;
  var periods=[...new Set(DATA.map(d=>d.period))].sort((a,b)=>periodSort(b)-periodSort(a));
  var yearGroups={};
  periods.forEach(p=>{ var y=parseInt(p); if(!yearGroups[y]) yearGroups[y]=[]; yearGroups[y].push(p); });
  var years=Object.keys(yearGroups).sort((a,b)=>b-a);
  document.querySelectorAll('#yearNav .sub-nav-btn').forEach((btn,i)=>{
    btn.classList.toggle('on', years[i]==yr);
  });
  showYearPanel(yr, yearGroups);
}
function showYearPanel(yr, yearGroups) {
  var all=DATA.filter(d=>parseInt(d.period)===parseInt(yr));
  var adopted=all.filter(d=>ADOPTED.has(d.award)).length, top=all.filter(d=>d.award==='최우수').length, rev=all.filter(d=>d.award==='심사중').length;
  var inner=yearGroups[yr].map(p=>{
    var list=DATA.filter(d=>d.period===p);
    var sub=p.includes('상반기')?'🌱 상반기':p.includes('하반기')?'🍂 하반기':'';
    var rows=list.map((d,i)=>'<tr onclick="openDetailFrom(\''+d.id+'\',\'year\')">'
      +'<td class="num">'+String(i+1).padStart(2,'0')+'</td>'+titleCell(d)
      +'<td>'+catBadge(d.category)+'</td><td>'+awardBadge(d.award)+'</td>'
      +'<td style="text-align:center">'+(d.pdf?(['png','jpg','jpeg'].includes(d.pdf.split('.').pop().toLowerCase())?'🖼️':'📄'):'')+'</td></tr>').join('');
    return (sub?'<tr style="background:#f6f8fd"><td colspan="5" style="padding:8px 14px 4px;font-weight:700;font-size:12px;color:#778;border-bottom:none">'+sub+'</td></tr>':'')+rows;
  }).join('');
  document.getElementById('yearArea').innerHTML=
    '<div class="yr-section"><div class="yr-hdr" style="background:linear-gradient(90deg,var(--navy),#2c4a8a)">'
    +'<div class="yr-title">'+yr+'년</div><div class="yr-chips">'
    +'<div class="yr-chip"><div class="yv yv1">'+all.length+'건</div><div class="yl">전체</div></div>'
    +'<div class="yr-chip"><div class="yv yv2">'+adopted+'건</div><div class="yl">채택</div></div>'
    +'<div class="yr-chip"><div class="yv yv3">'+rev+'건</div><div class="yl">심사중</div></div>'
    +'<div class="yr-chip"><div class="yv yv4">'+top+'건</div><div class="yl">최우수</div></div>'
    +'</div></div>'
    +'<div class="tbl-wrap"><table><thead><tr>'
    +'<th style="width:44px">번호</th><th>제목</th><th style="width:130px">분류</th><th style="width:100px">결과</th><th style="width:44px">PDF</th>'
    +'</tr></thead><tbody>'+inner+'</tbody></table></div></div>';
}

// ── 분류별 ───────────────────────────────────────────
var _curCat = null;
var CAT_LIST = ['관광아이디어발굴','조직혁신','사회적가치실현','기타'];
function renderCat() {
  var available=CAT_LIST.filter(c=>DATA.some(d=>d.category===c));
  if (!available.length) { document.getElementById('catArea').innerHTML='<div class="card"><div class="empty">등록된 제안이 없습니다.</div></div>'; return; }
  if (!_curCat || !available.includes(_curCat)) _curCat=available[0];
  document.getElementById('catNav').innerHTML=available.map(c=>
    '<button class="sub-nav-btn'+(c===_curCat?' on':'')+'" onclick="selectCat(\''+c+'\')">'+(CAT_ICON[c]||'📌')+' '+c+'</button>'
  ).join('');
  showCatPanel(_curCat);
}
function selectCat(cat) {
  _curCat=cat;
  var available=CAT_LIST.filter(c=>DATA.some(d=>d.category===c));
  document.querySelectorAll('#catNav .sub-nav-btn').forEach((btn,i)=>{
    btn.classList.toggle('on', available[i]===cat);
  });
  showCatPanel(cat);
}
function showCatPanel(cat) {
  var list=DATA.filter(d=>d.category===cat); if(!list.length) return;
  var adopted=list.filter(d=>ADOPTED.has(d.award)).length, rate=Math.round(adopted/list.length*100), c=CAT_COLOR[cat];
  var rows=list.map((d,i)=>'<tr onclick="openDetailFrom(\''+d.id+'\',\'cat\')">'
    +'<td class="num">'+String(i+1).padStart(2,'0')+'</td>'+titleCell(d)
    +'<td>'+periodBadge(d.period)+'</td><td>'+awardBadge(d.award)+'</td>'
    +'<td style="text-align:center">'+(d.pdf?(['png','jpg','jpeg'].includes(d.pdf.split('.').pop().toLowerCase())?'🖼️':'📄'):'')+'</td></tr>').join('');
  document.getElementById('catArea').innerHTML=
    '<div class="cat-section"><div class="cat-hdr" style="background:'+c+'">'
    +'<div class="cat-icon">'+CAT_ICON[cat]+'</div><div class="cat-name">'+cat+'</div>'
    +'<div class="cat-chips">'
    +'<div class="cat-chip"><div class="cv">'+list.length+'건</div><div class="cl">전체</div></div>'
    +'<div class="cat-chip"><div class="cv">'+adopted+'건</div><div class="cl">채택</div></div>'
    +'<div class="cat-chip"><div class="cv">'+rate+'%</div><div class="cl">채택률</div></div>'
    +'</div><div class="cat-bar-wrap"><div class="cat-bar"><div class="cat-bar-fill" style="width:'+rate+'%"></div></div><span class="cat-bar-lbl">채택률</span></div>'
    +'</div><div class="tbl-wrap"><table><thead><tr>'
    +'<th style="width:44px">번호</th><th>제목</th><th style="width:110px">기간</th><th style="width:100px">결과</th><th style="width:44px">PDF</th>'
    +'</tr></thead><tbody>'+rows+'</tbody></table></div></div>';
}

// ── 채택제안 ─────────────────────────────────────────
var _curGrade = null;
var GRADES = [
  {key:'최우수', bg:'#4a9ea8', icon:'🥇'},
  {key:'우수',   bg:'#5fc1c7', icon:'🥈'},
  {key:'장려',   bg:'#7ed4d4', icon:'🥉'},
  {key:'특별상', bg:'#a2e3df', icon:'🌟'},
];
function renderAdoptedHero() {
  var heroEl = document.getElementById('adoptedHero');
  if (!heroEl) return;
  var thisYear = new Date().getFullYear();
  var yearList = DATA.filter(function(d){ return ADOPTED.has(d.award) && parseInt(d.period) === thisYear; });
  if (!yearList.length) {
    heroEl.innerHTML =
      '<div class="adopted-hero">'
      +'<div class="adopted-hero-badge">🏆 올해의 채택제안</div>'
      +'<div class="adopted-hero-title">'+thisYear+'년 채택제안 하이라이트</div>'
      +'<div class="adopted-hero-sub">올해 채택된 제안에 응원과 의견을 남겨보세요! 💬</div>'
      +'<div class="adopted-hero-empty">🌱 '+thisYear+'년 채택된 제안이 아직 없습니다.<br><span>채택제안이 등록되면 여기에 표시됩니다.</span></div>'
      +'</div>';
    return;
  }
  var awardColors = {'최우수':'#4a9ea8','우수':'#5fc1c7','장려':'#7ed4d4','특별상':'#a2e3df'};
  var items = yearList.map(function(d, i) {
    var c = awardColors[d.award] || '#888';
    return '<div class="hero-item" style="animation-delay:'+(i*0.08)+'s" onclick="openDetailFrom(\''+d.id+'\',\'adopted\')">'
      +'<span class="hero-item-award" style="background:'+c+'">'+d.award+'</span>'
      +'<span class="hero-item-title">'+esc(d.title)+'</span>'
      +'</div>';
  }).join('');
  heroEl.innerHTML =
    '<div class="adopted-hero">'
    +'<div class="adopted-hero-badge">🏆 '+thisYear+'년 채택제안 <span style="font-weight:400;opacity:.7">'+yearList.length+'건</span></div>'
    +'<div class="hero-list">'+items+'</div>'
    +'</div>';
}
function renderAdopted() {
  renderAdoptedHero();
  var adoptedList=DATA.filter(d=>ADOPTED.has(d.award));
  if (!adoptedList.length) {
    document.getElementById('adoptedNav').innerHTML='';
    document.getElementById('adoptedArea').innerHTML=''; return;
  }
  var available=GRADES.filter(g=>adoptedList.some(d=>d.award===g.key));
  if (!_curGrade || !available.find(g=>g.key===_curGrade)) _curGrade=available[0].key;
  document.getElementById('adoptedNav').innerHTML=available.map(g=>{
    var cnt=adoptedList.filter(d=>d.award===g.key).length;
    var on=_curGrade===g.key;
    return '<button class="sub-nav-btn'+(on?' on':'')+'" onclick="selectGrade(\''+g.key+'\')">'
      +g.icon+' '+g.key+'</button>';
  }).join('');
  showAdoptedPanel(_curGrade);
}
function selectGrade(key) {
  _curGrade=key;
  var adoptedList=DATA.filter(d=>ADOPTED.has(d.award));
  var available=GRADES.filter(g=>adoptedList.some(d=>d.award===g.key));
  document.querySelectorAll('#adoptedNav .sub-nav-btn').forEach((btn,i)=>{
    btn.classList.toggle('on', available[i] && available[i].key===key);
  });
  showAdoptedPanel(key);
}
function showAdoptedPanel(key) {
  var g=GRADES.find(x=>x.key===key);
  var list=DATA.filter(d=>d.award===key);
  list.sort((a,b)=>periodSort(b.period)-periodSort(a.period));
  var rows=list.map((d,i)=>'<tr onclick="openDetailFrom(\''+d.id+'\',\'adopted\')">'    +'<td class="num">'+String(i+1).padStart(2,'0')+'</td>'+titleCell(d)    +'<td>'+catBadge(d.category)+'</td><td>'+periodBadge(d.period)+'</td>'    +'<td style="text-align:center">'+(d.pdf?(['png','jpg','jpeg'].includes(d.pdf.split('.').pop().toLowerCase())?'🖼️':'📄'):'')+'</td></tr>').join('');
  var years=[...new Set(list.map(d=>parseInt(d.period)))].sort((a,b)=>b-a);
  var yearRange=years.length>1?years[years.length-1]+'~'+years[0]+'년':years[0]+'년';
  document.getElementById('adoptedArea').innerHTML=
    '<div class="yr-section"><div class="yr-hdr" style="background:'+g.bg+'">'    +'<div class="yr-title">'+g.icon+' '+g.key+'</div>'    +'<div class="yr-chips">'    +'<div class="yr-chip"><div class="yv yv1">'+list.length+'건</div><div class="yl">전체</div></div>'    +(years.length?'<div class="yr-chip"><div class="yv" style="color:#fff;font-size:13px">'+yearRange+'</div><div class="yl">기간</div></div>':'')    +'</div></div>'    +'<div class="tbl-wrap"><table><thead><tr>'    +'<th style="width:44px">번호</th><th>제목</th><th style="width:130px">분류</th><th style="width:110px">기간</th><th style="width:44px">PDF</th>'    +'</tr></thead><tbody>'+rows+'</tbody></table></div></div>';
}


// ── 수정 ─────────────────────────────────────────────
function openEdit(id) {
  var d=DATA.find(x=>String(x.id)===String(id)); if(!d) return;
  _editId=id;
  document.getElementById('e_title').value   =d.title   ||'';
  document.getElementById('e_proposer').value=d.proposer||'';
  document.getElementById('e_period').value  =d.period  ||'';
  document.getElementById('e_category').value=d.category||'';
  document.getElementById('e_award').value   =d.award   ||'';
  document.getElementById('e_summary').value =d.summary ||'';
  document.getElementById('e_pdf').value     =d.pdf     ||'';
  // 부서
  var sel=document.getElementById('e_dept'), etc=document.getElementById('e_dept_etc');
  var opts=Array.from(sel.options).map(o=>o.value);
  if (opts.includes(d.dept)) { sel.value=d.dept; etc.style.display='none'; }
  else { sel.value='기타(직접입력)'; etc.style.display='block'; etc.value=d.dept||''; }
  document.getElementById('editOverlay').classList.add('on');
}
function closeEdit() { document.getElementById('editOverlay').classList.remove('on'); _editId=null; }
function saveEdit() {
  var title  =document.getElementById('e_title').value.trim();
  var proposer=document.getElementById('e_proposer').value.trim();
  var summary=document.getElementById('e_summary').value.trim();
  if (!title||!summary) { showToast('제목, 요약은 필수입니다','err'); return; }
  var idx=DATA.findIndex(x=>String(x.id)===String(_editId)); if(idx===-1) return;
  var newPeriod = document.getElementById('e_period').value;
  var oldSeq = DATA[idx].seq || '';
  var newSeq = newPeriod && oldSeq ? oldSeq.replace(/^\d{4}/, newPeriod) : oldSeq;
  DATA[idx]={...DATA[idx], title, proposer,
    dept:    getDept('e_dept','e_dept_etc'),
    period:  newPeriod,
    category:document.getElementById('e_category').value,
    award:   document.getElementById('e_award').value,
    summary,
    pdf:     document.getElementById('e_pdf').value.trim(),
    seq:     newSeq,
  };
  if (!_gToken) { showToast('🔑 Google 로그인 후 수정 가능합니다','err'); return; }
  closeEdit(); showToast('수정되었습니다!','ok'); renderAll();
  saveToSheet(DATA[idx], oldSeq);
  // 상세 화면이 열려 있으면 갱신
  if (_curId===DATA[idx].id) openDetail(_curId);
}
function deleteItem() {
  if (!_gToken) { showToast('🔑 Google 로그인 후 삭제 가능합니다','err'); return; }
  if (!confirm('이 제안을 삭제하시겠습니까?')) return;
  var d = DATA.find(x=>String(x.id)===String(_editId));
  DATA=DATA.filter(x=>x.id!==_editId);
  if (d) deleteFromSheet(d.seq);
  closeEdit(); closeDetail(); showToast('삭제되었습니다','ok'); renderAll();
}

