var _donutMascotTimer = null;
var _lastMascotIdx = -1;
function showDonutMascot() {
  var el = document.getElementById('donutMascot');
  if (!el) return;
  if (el.style.opacity === '1') return;
  var idx;
  do { idx = Math.floor(Math.random()*_DONUT_MASCOTS.length); } while(idx === _lastMascotIdx && _DONUT_MASCOTS.length > 1);
  _lastMascotIdx = idx;
  el.src = _DONUT_MASCOTS[idx];
  el.style.transform = 'translate(-50%,-60%) scale(1)';
  el.style.opacity = '1';
}
function hideDonutMascot() {
  var el = document.getElementById('donutMascot');
  if (!el) return;
  el.style.transform = 'translate(-50%,-60%) scale(0)';
  el.style.opacity = '0';
}

