document.addEventListener('mouseover', function(e) {
  var wrap = e.target.closest('.tip-wrap');
  if (!wrap) return;
  var box = wrap.querySelector('.tip-box');
  if (!box) return;
  var rect = wrap.getBoundingClientRect();
  var boxH = 200; // 예상 높이
  var spaceBelow = window.innerHeight - rect.bottom;
  if (spaceBelow < boxH + 20) {
    box.style.top = '';
    box.style.bottom = (window.innerHeight - rect.top + 6) + 'px';
  } else {
    box.style.bottom = '';
    box.style.top = (rect.bottom + 6) + 'px';
  }
  box.style.left = Math.min(rect.left, window.innerWidth - 430) + 'px';
});
