var _similarTimer = null;
var STOP_WORDS = '의,를,을,이,가,은,는,에,에서,으로,로,와,과,및,등,한,할,하는,하여,위한,통한,위해,통해,있는,되는,것,수,대한,관련,추진,운영,도입,제안,개선,실시,방안,활용,필요,시,후,중,내,대,더,또한,아울러,현재,기존,공사,대전,대전관광공사,직원,사업,행사,시민'.split(',');

function extractKeywords(text) {
  if (!text) return [];
  var words = text.replace(/[○●■□▪▸\-\(\)\[\]\/,\.:;!?\d]/g, ' ')
    .split(/\s+/)
    .filter(function(w) { return w.length >= 2 && STOP_WORDS.indexOf(w) < 0; });
  var unique = [];
  words.forEach(function(w) { if (unique.indexOf(w) < 0) unique.push(w); });
  return unique;
}

// (유사검색 기능 삭제됨)

function initSubmitTab() {
  var dateEl = document.getElementById('sf-date');
  if (dateEl && !dateEl.value) {
    dateEl.value = new Date().toISOString().split('T')[0];
  }
  renderSubmitList();
}

function renderSubmitList() {
  var body = document.getElementById('submitListBody');
  if (!body) return;
  var filter = (document.getElementById('submitListFilter') || {}).value || 'all';
  var items = DATA.filter(function(d) {
    if (filter === 'all') return d.award === '심사중' || d.status === '접수완료';
    return d.award === filter || d.status === filter;
  }).sort(function(a, b) { return (b.submittedAt || b.id || '').toString().localeCompare((a.submittedAt || a.id || '').toString()); });

  if (!items.length) {
    body.innerHTML = '<p style="text-align:center;color:#aaa;padding:20px;font-size:13px">접수된 제안이 없습니다.</p>';
    return;
  }
  var html = '<table class="submit-list-table"><thead><tr><th>접수일</th><th>제목</th><th>제안부문</th><th>상태</th></tr></thead><tbody>';
  items.forEach(function(d) {
    var date = (d.period || d.submittedAt || '').toString().substring(0, 10);
    html += '<tr onclick="openDetail(\'' + d.id + '\')" style="cursor:pointer">' +
      '<td class="sl-date">' + date + '</td>' +
      '<td class="sl-title">' + esc(d.title) + '</td>' +
      '<td>' + catBadge(d.category) + '</td>' +
      '<td>' + awardBadge(d.award) + '</td>' +
    '</tr>';
  });
  html += '</tbody></table>';
  body.innerHTML = html;
}

function showPickedFile() {
  var fileInput = document.getElementById('sf-file');
  var picked = document.getElementById('sf-picked');
  if (fileInput && fileInput.files && fileInput.files[0]) {
    var f = fileInput.files[0];
    var size = f.size < 1024*1024 ? Math.round(f.size/1024) + 'KB' : (f.size/(1024*1024)).toFixed(1) + 'MB';
    picked.textContent = '📄 ' + f.name + ' (' + size + ')';
  } else if (picked) {
    picked.textContent = '';
  }
}

function clearSubmitForm() {
  ['sf-name','sf-dept','sf-title','sf-reason','sf-method','sf-save','sf-revenue','sf-effect','sf-target-dept'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  document.getElementById('sf-category').selectedIndex = 0;
  document.getElementById('sf-date').value = new Date().toISOString().split('T')[0];
  document.getElementById('sf-file').value = '';
  var picked = document.getElementById('sf-picked');
  if (picked) picked.textContent = '';
}

function submitProposal() {
  var name = document.getElementById('sf-name').value.trim();
  var dept = document.getElementById('sf-dept').value.trim();
  var cat = document.getElementById('sf-category').value;
  var title = document.getElementById('sf-title').value.trim();
  var reason = document.getElementById('sf-reason').value.trim();
  var method = document.getElementById('sf-method').value.trim();
  var fileInput = document.getElementById('sf-file');
  var file = fileInput && fileInput.files && fileInput.files[0];
  if (!name) return alert('성명을 입력해주세요.');
  if (!dept) return alert('소속을 입력해주세요.');
  if (!cat) return alert('제안부문을 선택해주세요.');
  if (!title) return alert('제목을 입력해주세요.');
  if (!file) return alert('제안서 PDF 파일을 첨부해주세요.');
  if (file && !file.name.toLowerCase().endsWith('.pdf')) return alert('PDF 파일만 접수 가능합니다.');
  var effect = [
    document.getElementById('sf-save').value ? '예산절감: ' + document.getElementById('sf-save').value : '',
    document.getElementById('sf-revenue').value ? '수입증대: ' + document.getElementById('sf-revenue').value : '',
    document.getElementById('sf-effect').value || ''
  ].filter(Boolean).join(' / ');
  var summary = '● ' + reason.split('\n').filter(Boolean).join('\n● ') +
    '\n● ' + method.split('\n').filter(Boolean).join('\n● ');
  if (effect) summary += '\n● 기대효과: ' + effect;
  var now = new Date();
  var yr = now.getFullYear().toString();
  var half = now.getMonth() < 6 ? '상반기' : '하반기';
  var keywords = extractKeywords(title + ' ' + reason).slice(0, 5).map(function(k){return '#'+k;}).join(' ');
  var dateVal = document.getElementById('sf-date').value || yr + '-01-01';
  var targetDept = document.getElementById('sf-target-dept').value || '';

  // Apps Script 모드
  if (SCRIPT_URL) {
    var btn = document.querySelector('#tab-submit .btn-submit-full');
    if (btn) { btn.disabled = true; btn.textContent = '접수 중...'; }
    showLoadingOverlay('제안서 접수 중...');

    var doSubmit = function(fileData, fileName, fileType, fileSize) {
      apiPost({
        action: 'submitProposal',
        title: title, proposer: name, dept: dept, date: dateVal,
        category: cat, targetDept: targetDept,
        reason: reason, method: method,
        effectSave: document.getElementById('sf-save').value || '',
        effectRevenue: document.getElementById('sf-revenue').value || '',
        effectEtc: document.getElementById('sf-effect').value || '',
        keywords: keywords,
        fileData: fileData || '', fileName: fileName || '',
        fileType: fileType || '', fileSize: fileSize || 0
      }).then(function(res) {
        hideLoadingOverlay();
        if (btn) { btn.disabled = false; btn.textContent = '제안서 접수'; }
        if (res.ok) {
          alert('✅ 제안서가 접수되었습니다!\n제안번호: ' + res.id);
          clearSubmitForm();
          try { switchTab('list', document.querySelector('.nav-btn')); } catch(e) {}
          try { loadFromSheet(); } catch(e) {}
        } else {
          alert('❌ 접수 실패: ' + (res.error || '알 수 없는 오류'));
        }
      }).catch(function(e) {
        hideLoadingOverlay();
        if (btn) { btn.disabled = false; btn.textContent = '제안서 접수'; }
        alert('❌ 서버 오류: ' + e.message);
      });
    };

    if (file) {
      toB64(file).then(function(b64) { doSubmit(b64, file.name, file.type, file.size); });
    } else {
      doSubmit();
    }
    return;
  }

  // 폴백: 로컬 DATA에 추가
  var d = {
    id: 'sub_' + Date.now(), title: title, proposer: name, dept: dept,
    period: yr + ' ' + half, category: cat, award: '심사중',
    summary: summary, keywords: keywords, pdf: ''
  };
  DATA.push(d);
  alert('✅ 제안서가 접수되었습니다!\n\n※ 현재 목록에 추가되었습니다.\n   서버 연동 후 자동 저장됩니다.');
  renderAll();
  clearSubmitForm();
  switchTab('list', document.querySelector('.nav-btn'));
}

// ══════════════════════════════════════════════════════════
// ██  검토·심사 탭  ██
// ══════════════════════════════════════════════════════════

var _rvMode = null; // 'review' or 'judge'
var _rvCode = '';

// 폴백용 로컬 코드 (SCRIPT_URL 미설정 시)
var REVIEW_CODES = {
  'review-2025': { type: 'review', label: '2025년 전체 검토', filter: function(d) { return (d.period||'').indexOf('2025') >= 0; } },
  'review-2026': { type: 'review', label: '2026년 전체 검토', filter: function(d) { return (d.period||'').indexOf('2026') >= 0; } },
  'review-test': { type: 'review', label: '테스트 검토', filter: function() { return true; } }
};
var JUDGE_CODES = {
  'judge-2025': { type: 'judge', label: '2025년 전체 심사', filter: function(d) { return (d.period||'').indexOf('2025') >= 0; } },
  'judge-2026': { type: 'judge', label: '2026년 전체 심사', filter: function(d) { return (d.period||'').indexOf('2026') >= 0; } },
  'judge-test': { type: 'judge', label: '테스트 심사', filter: function() { return true; } }
};

var SCORE_ITEMS = [
  { key: 'feasibility', name: '실시가능성', max: 20, options: [20,16,12,8,4], labels: ['매우크다','다소크다','보통','약간있다','없다'] },
  { key: 'creativity', name: '창의성', max: 15, options: [15,12,9,6,3], labels: ['획기적착상','다소독창적','보통','일부모방','전부모방'] },
  { key: 'effectiveness', name: '효과성', max: 15, options: [15,12,9,6,3], labels: ['5억이상','3억이상','1억이상','5천만원이상','5천만원미만'] },
  { key: 'efficiency', name: '효율성', max: 15, options: [15,12,9,6,3], labels: ['매우크다','다소크다','보통','약간있다','없다'] },
  { key: 'scope', name: '적용범위', max: 15, options: [15,12,9,6,3], labels: ['전부서','다수부서','일부부서','소속부서','단위업무'] },
  { key: 'duration', name: '지속성', max: 10, options: [10,8,6,4,2], labels: ['10년이상','5년이상','3년이상','1년이상','1년미만'] },
  { key: 'effort', name: '노력도/구체성', max: 10, options: [10,8,6,4,2], labels: ['매우크다','다소크다','보통','약간있다','없다'] }
];

// ── 관리 탭 통합 로그인 ──
function manageLogin() {
  var input = document.getElementById('mg-input').value.trim();
  var errEl = document.getElementById('mg-error');
  if (!input) { errEl.textContent = '비밀번호 또는 코드를 입력하세요.'; errEl.style.display = 'block'; return; }
  errEl.style.display = 'none';

  if (SCRIPT_URL) {
    // 먼저 관리자 비밀번호로 시도
    api({ action: 'getProposalsAdmin', pw: input }).then(function(adminRes) {
      if (!adminRes.error) {
        // 관리자 인증 성공
        ADMIN_PW = input;
        isAdmin = true;
        document.getElementById('mg-lock').style.display = 'none';
        document.getElementById('mg-admin').style.display = 'block';
        showMgPanel('mg-inbox', document.querySelector('.admin-nav-btn'));
        loadFromSheet().then(function() { renderMgInbox(); });
        return;
      }
      // 관리자 실패 → 검토/심사 코드 시도
      api({ action: 'verifyCode', code: input }).then(function(res) {
        if (!res.ok) { errEl.textContent = res.error || '유효하지 않은 코드 또는 비밀번호입니다.'; errEl.style.display = 'block'; return; }
        _rvCode = input;
        _rvMode = res.type;
        document.getElementById('mg-lock').style.display = 'none';
        if (res.type === 'review') {
          document.getElementById('mg-review').style.display = 'block';
          api({ action: 'getReviewsByCode', code: input }).then(function(data) {
            if (data.ok) renderReviewListFromServer(data);
          });
        } else {
          document.getElementById('mg-judge').style.display = 'block';
          api({ action: 'getScoresByCode', code: input }).then(function(data) {
            if (data.ok) renderJudgeListFromServer(data);
          });
        }
      }).catch(function(e) { errEl.textContent = '서버 연결 실패'; errEl.style.display = 'block'; });
    }).catch(function(e) { errEl.textContent = '서버 연결 실패'; errEl.style.display = 'block'; });
    return;
  }

  // 폴백: 로컬 코드 검증
  var cfg = REVIEW_CODES[input.toLowerCase()] || JUDGE_CODES[input.toLowerCase()];
  if (!cfg) { errEl.textContent = '유효하지 않은 코드 또는 비밀번호입니다.'; errEl.style.display = 'block'; return; }
  _rvCode = input;
  _rvMode = cfg.type;
  document.getElementById('mg-lock').style.display = 'none';
  if (cfg.type === 'review') {
    document.getElementById('mg-review').style.display = 'block';
    renderReviewList(cfg);
  } else {
    document.getElementById('mg-judge').style.display = 'block';
    renderJudgeList(cfg);
  }
}

function manageLogout() {
  _rvMode = null;
  _rvCode = '';
  isAdmin = false;
  ADMIN_PW = '';
  document.getElementById('mg-lock').style.display = 'block';
  document.getElementById('mg-admin').style.display = 'none';
  document.getElementById('mg-review').style.display = 'none';
  document.getElementById('mg-judge').style.display = 'none';
  document.getElementById('mg-input').value = '';
  document.getElementById('mg-error').style.display = 'none';
  loadFromSheet(); // 비관리자 모드로 다시 로드
}

function showMgPanel(id, btn) {
  document.querySelectorAll('#mg-admin .admin-panel').forEach(function(el) { el.classList.remove('active'); });
  document.querySelectorAll('#mg-admin .admin-nav-btn').forEach(function(el) { el.classList.remove('active'); });
  document.getElementById(id).classList.add('active');
  if (btn) btn.classList.add('active');
  if (id === 'mg-inbox') renderMgInbox();
  if (id === 'mg-codes') loadCodes();
  if (id === 'mg-tracking') { loadTracking().then(function() { initMgTracking(); }); }
}

function renderMgInbox() {
  var body = document.getElementById('mgInboxBody');
  if (!body) return;
  var filter = (document.getElementById('mgInboxFilter') || {}).value || 'all';
  var items = DATA.filter(function(d) {
    if (filter === 'all') return d.award === '심사중' || d.award === '접수완료' || d.status === '접수완료';
    return d.award === filter || d.status === filter;
  });

  if (!items.length) {
    body.innerHTML = '<p style="text-align:center;color:#aaa;padding:20px;font-size:13px">접수된 제안이 없습니다.</p>';
    var split = document.getElementById('inbox-split'); if (split) split.style.display = 'none';
    return;
  }
  var html = '<table class="submit-list-table"><thead><tr><th>접수일</th><th>제목</th><th>제안자</th><th>부서</th><th>제안부문</th><th>상태</th></tr></thead><tbody>';
  items.forEach(function(d, i) {
    var date = (d.period || d.submittedAt || '').toString().substring(0, 10);
    html += '<tr onclick="openInboxDetail(\'' + d.id + '\',this)" style="cursor:pointer" class="inbox-row">' +
      '<td class="sl-date">' + date + '</td>' +
      '<td class="sl-title">' + esc(d.title) + '</td>' +
      '<td>' + esc(d.proposer || '') + '</td>' +
      '<td>' + esc(d.dept || '') + '</td>' +
      '<td>' + catBadge(d.category) + '</td>' +
      '<td>' + awardBadge(d.award) + '</td>' +
    '</tr>';
  });
  html += '</tbody></table>';
  body.innerHTML = html;
}

function openInboxDetail(id, rowEl) {
  var d = DATA.find(function(x) { return String(x.id) === String(id); });
  if (!d) return;
  // 행 활성화
  document.querySelectorAll('.inbox-row').forEach(function(r) { r.classList.remove('active-row'); });
  if (rowEl) rowEl.classList.add('active-row');
  // 분할화면 표시
  var split = document.getElementById('inbox-split');
  split.style.display = 'flex';
  // 좌측: 제안 상세 + 첨부파일 미리보기
  var inboxPdfHtml = '';
  var inboxFileUrl = d.driveUrl || '';
  var inboxFileName = d.pdf || '';
  if (inboxFileUrl && inboxFileUrl.indexOf('drive.google.com') >= 0) {
    var inboxFileId = inboxFileUrl.match(/\/d\/([^\/]+)/) || inboxFileUrl.match(/[?&]id=([^&]+)/);
    var inboxPreview = inboxFileId ? 'https://drive.google.com/file/d/' + inboxFileId[1] + '/preview' : inboxFileUrl;
    inboxPdfHtml = '<div style="margin-top:16px;border-top:1px solid #e8edf5;padding-top:12px">' +
      '<div style="font-size:13px;font-weight:600;color:var(--navy);margin-bottom:8px">📎 ' + esc(inboxFileName) + '</div>' +
      '<iframe src="' + inboxPreview + '" style="width:100%;height:500px;border:1px solid #e8edf5;border-radius:8px" allowfullscreen></iframe>' +
      '<a href="' + esc(inboxFileUrl) + '" target="_blank" style="display:inline-block;margin-top:6px;color:var(--blue);font-size:12px">🔗 새 탭에서 열기</a>' +
    '</div>';
  } else if (inboxFileName) {
    inboxPdfHtml = '<div style="margin-top:12px"><a href="' + esc(inboxFileUrl || '#') + '" target="_blank" style="color:var(--blue);font-size:13px">📎 ' + esc(inboxFileName) + '</a></div>';
  }
  document.getElementById('inbox-detail-area').innerHTML =
    '<div style="margin-bottom:10px">' + catBadge(d.category) + ' ' + awardBadge(d.award) + '</div>' +
    '<h3 style="font-size:17px;font-weight:800;color:var(--navy);margin-bottom:12px">' + esc(d.title) + '</h3>' +
    '<div style="font-size:13px;color:#555;line-height:1.8">' + fmtSummary(d.summary) + '</div>' +
    inboxPdfHtml;
  // 우측: 제안 정보
  document.getElementById('inbox-info-area').innerHTML =
    '<div class="info-item"><span class="info-label">제안자</span><span>' + esc(d.proposer || '-') + '</span></div>' +
    '<div class="info-item"><span class="info-label">부서</span><span>' + esc(d.dept || '-') + '</span></div>' +
    '<div class="info-item"><span class="info-label">제안부문</span><span>' + esc(d.category || '-') + '</span></div>' +
    '<div class="info-item"><span class="info-label">접수일</span><span>' + esc(d.period || '-') + '</span></div>' +
    '<div class="info-item"><span class="info-label">상태</span><span>' + (d.award || '-') + '</span></div>' +
    (d.keywords ? '<div class="info-item"><span class="info-label">키워드</span><span>' + fmtKeywords(d.keywords) + '</span></div>' : '');
  split.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

// 기존 함수 호환성 유지
function verifyCode() { manageLogin(); }
function exitReview() { manageLogout(); }

// ── 코드 관리 ──
function toggleCodeForm() {
  var form = document.getElementById('codeCreateForm');
  form.style.display = form.style.display === 'none' ? 'block' : 'none';
}

function loadCodes() {
  var body = document.getElementById('mgCodesBody');
  if (!body) return;
  var syncText = document.getElementById('code-sync-text');
  var syncBox = document.getElementById('code-sync-box');
  if (!SCRIPT_URL) {
    body.innerHTML = '<p style="text-align:center;color:#aaa;padding:20px">Apps Script 미연결</p>';
    if (syncText) syncText.textContent = '⚠️ Apps Script 미연결';
    if (syncBox) { syncBox.style.background = '#fef2f2'; syncBox.style.borderColor = '#fca5a5'; syncBox.style.color = '#991b1b'; }
    return;
  }
  body.innerHTML = '<p style="text-align:center;color:#aaa;padding:20px">불러오는 중...</p>';
  if (syncText) syncText.textContent = '불러오는 중...';
  if (syncBox) { syncBox.style.background = '#fefce8'; syncBox.style.borderColor = '#fde047'; syncBox.style.color = '#854d0e'; }
  api({ action: 'getCodes', pw: ADMIN_PW }).then(function(res) {
    var codes = Array.isArray(res) ? res : (res && res.codes ? res.codes : []);
    var countEl = document.getElementById('code-member-count');
    if (countEl) countEl.textContent = '(' + codes.length + '명)';
    if (syncText) syncText.textContent = '✅ 위원 명단 로드 완료 (' + codes.length + '명, Sheets 연동됨)';
    if (syncBox) { syncBox.style.background = '#f0fdf4'; syncBox.style.borderColor = '#86efac'; syncBox.style.color = '#15803d'; }
    if (!codes.length) { body.innerHTML = '<div style="text-align:center;padding:30px;color:#94a3b8;font-size:13px"><div style="font-size:32px;margin-bottom:8px">👥</div><div>등록된 위원이 없습니다.<br>Excel 파일을 업로드하거나 [+ 개별 추가] 버튼으로 추가하세요.</div></div>'; return; }
    var html = '<table class="submit-list-table"><thead><tr><th>역할</th><th>이름</th><th>부서</th><th>연도</th><th>로그인 코드</th><th></th></tr></thead><tbody>';
    codes.forEach(function(c) {
      var typeBadge = c.type === 'review'
        ? '<span style="background:#e3f2fd;color:#1565c0;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700">검토위원</span>'
        : '<span style="background:#fce4ec;color:#c62828;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700">심사위원</span>';
      html += '<tr><td>' + typeBadge + '</td><td style="font-weight:600">' + esc(c.assignedTo || '-') + '</td>' +
        '<td>' + esc(c.label || '-') + '</td><td>' + esc(c.targetYear || '') + '</td>' +
        '<td><code style="background:#f0f3f9;padding:2px 8px;border-radius:4px;font-size:13px;font-weight:600;user-select:all">' + esc(c.code) + '</code></td>' +
        '<td><button class="btn-cancel" style="padding:3px 10px;font-size:11px" onclick="deleteCode(\'' + c.id + '\')">삭제</button></td></tr>';
    });
    html += '</tbody></table>';
    body.innerHTML = html;
  }).catch(function() {
    body.innerHTML = '<p style="color:var(--rose);text-align:center;padding:20px">로드 실패</p>';
    if (syncText) syncText.textContent = '⚠️ Sheets 연결 실패';
    if (syncBox) { syncBox.style.background = '#fef2f2'; syncBox.style.borderColor = '#fca5a5'; syncBox.style.color = '#991b1b'; }
  });
}

function createCode() {
  if (!SCRIPT_URL) return alert('Apps Script 미연결');
  var type = document.getElementById('cc-type').value;
  var year = document.getElementById('cc-year').value.trim();
  var assignee = document.getElementById('cc-assignee').value.trim();
  var label = document.getElementById('cc-label').value.trim();
  if (!assignee) return alert('이름을 입력해주세요.');
  apiPost({
    action: 'manageCode', pw: ADMIN_PW, op: 'create',
    type: type, targetYear: year, code: '', label: label, assignedTo: assignee
  }).then(function(res) {
    if (res.ok) {
      alert('✅ 위원 추가 완료!\n\n이름: ' + assignee + '\n로그인 코드: ' + res.code + '\n\n이 코드를 해당 위원에게 전달하세요.');
      toggleCodeForm();
      document.getElementById('cc-assignee').value = '';
      document.getElementById('cc-label').value = '';
      loadCodes();
    } else { alert('❌ 추가 실패: ' + (res.error || '')); }
  });
}

function deleteCode(id) {
  if (!confirm('이 위원을 삭제하시겠습니까?')) return;
  apiPost({ action: 'manageCode', pw: ADMIN_PW, op: 'delete', id: id }).then(function(res) {
    if (res.ok) { alert('삭제되었습니다.'); loadCodes(); }
    else alert('삭제 실패: ' + (res.error || ''));
  });
}

function uploadCodeExcel(input) {
  var file = input.files[0]; if (!file) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    var wb = XLSX.read(new Uint8Array(e.target.result), { type: 'array' });
    var data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]], { header: 1 });
    // 헤더 감지
    var start = (data[0] && (String(data[0][0]).includes('역할') || String(data[0][0]).includes('유형'))) ? 1 : 0;
    var parsed = [];
    for (var i = start; i < data.length; i++) {
      var r = data[i]; if (!r || !r[0]) continue;
      var role = String(r[0] || '').trim();
      var name = String(r[1] || '').trim();
      var dept = String(r[2] || '').trim();
      if (!name) continue;
      var type = (role.indexOf('심사') >= 0) ? 'judge' : 'review';
      parsed.push({ type: type, name: name, dept: dept });
    }
    if (!parsed.length) { alert('파일에서 데이터를 읽을 수 없습니다.\n형식: 역할 | 이름 | 부서'); return; }
    if (!confirm(parsed.length + '명의 위원을 일괄 등록합니다.\n(기존 위원 목록에 추가됩니다)')) return;
    document.getElementById('code-xlsx-label').textContent = '⏳ 등록 중... (0/' + parsed.length + ')';
    var done = 0;
    var results = [];
    function next() {
      if (done >= parsed.length) {
        document.getElementById('code-xlsx-label').textContent = '✅ ' + file.name + ' (' + parsed.length + '명 등록 완료)';
        var msg = '✅ ' + parsed.length + '명 등록 완료!\n\n';
        results.forEach(function(r) { msg += r.type + ' | ' + r.name + ' | 코드: ' + r.code + '\n'; });
        alert(msg);
        loadCodes();
        return;
      }
      var p = parsed[done];
      apiPost({
        action: 'manageCode', pw: ADMIN_PW, op: 'create',
        type: p.type, targetYear: new Date().getFullYear().toString(), code: '', label: p.dept, assignedTo: p.name
      }).then(function(res) {
        results.push({ type: p.type === 'judge' ? '심사' : '검토', name: p.name, code: res.code || '?' });
        done++;
        document.getElementById('code-xlsx-label').textContent = '⏳ 등록 중... (' + done + '/' + parsed.length + ')';
        next();
      }).catch(function() { done++; next(); });
    }
    next();
  };
  reader.readAsArrayBuffer(file);
  input.value = '';
}

function clearAllCodes() {
  if (!confirm('⚠️ 등록된 모든 위원을 삭제하시겠습니까?\n이 작업은 되돌릴 수 없습니다.')) return;
  api({ action: 'getCodes', pw: ADMIN_PW }).then(function(res) {
    var codes = Array.isArray(res) ? res : (res && res.codes ? res.codes : []);
    if (!codes.length) { alert('삭제할 위원이 없습니다.'); return; }
    var done = 0;
    function delNext() {
      if (done >= codes.length) { alert('✅ 전체 초기화 완료'); loadCodes(); return; }
      apiPost({ action: 'manageCode', pw: ADMIN_PW, op: 'delete', id: codes[done].id }).then(function() { done++; delNext(); }).catch(function() { done++; delNext(); });
    }
    delNext();
  });
}

function renderReviewList(cfg) {
  var items = DATA.filter(cfg.filter);
  var el = document.getElementById('rv-review-list');
  if (!items.length) { el.innerHTML = '<p style="text-align:center;color:#aaa;padding:40px">배정된 제안이 없습니다.</p>'; return; }
  var html = '';
  items.forEach(function(d) {
    html += '<div class="rv-card">' +
      '<div class="rv-card-head">' + catBadge(d.category) + ' <b>' + esc(d.title) + '</b></div>' +
      '<div class="rv-card-summary">' + fmtSummary(d.summary) + '</div>' +
      '<div class="rv-card-field">' +
        '<label>검토의견</label>' +
        '<textarea id="rv-opinion-' + d.id + '" rows="4" placeholder="○ 담당부서 검토의견을 입력하세요"></textarea>' +
        '<button class="btn-save" onclick="saveReviewOpinion(\'' + d.id + '\')" style="margin-top:8px">저장</button>' +
      '</div>' +
    '</div>';
  });
  el.innerHTML = html;
}

function saveReviewOpinion(id, title) {
  var val = document.getElementById('rv-opinion-' + id).value.trim();
  if (!val) return alert('검토의견을 입력해주세요.');
  if (SCRIPT_URL) {
    var btn = document.querySelector('#rv-opinion-' + id + ' ~ .btn-save') || event.target;
    if (btn) { btn.disabled = true; btn.textContent = '저장 중...'; }
    apiPost({
      action: 'saveReview', code: _rvCode,
      proposalId: id, proposalTitle: title || '', opinion: val
    }).then(function(res) {
      if (btn) { btn.disabled = false; btn.textContent = '저장'; }
      if (res.ok) alert('✅ 검토의견이 저장되었습니다.' + (res.updated ? ' (수정됨)' : ''));
      else alert('❌ 저장 실패: ' + (res.error || ''));
    }).catch(function() {
      if (btn) { btn.disabled = false; btn.textContent = '저장'; }
      alert('❌ 서버 오류');
    });
    return;
  }
  alert('✅ 검토의견이 저장되었습니다.');
}

// ── 검토: 목록 + 분할화면 ──
var _reviewProposals = [];
var _curReviewIdx = -1;

function renderReviewListFromServer(data) {
  _reviewProposals = data.proposals || [];
  var el = document.getElementById('rv-review-list');
  var done = _reviewProposals.filter(function(p) { return p.existingReview; }).length;
  var progEl = document.getElementById('rv-progress');
  if (progEl) progEl.textContent = done + '/' + _reviewProposals.length + '건 완료';
  if (!_reviewProposals.length) { el.innerHTML = '<p style="text-align:center;color:#aaa;padding:40px">배정된 제안이 없습니다.</p>'; return; }
  var html = '<table class="submit-list-table"><thead><tr><th>제안부문</th><th>제목</th><th>상태</th></tr></thead><tbody>';
  _reviewProposals.forEach(function(p, i) {
    var isDone = p.existingReview;
    var statusHtml = isDone
      ? '<span style="background:#dcfce7;color:#15803d;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700">✅ 검토완료</span>'
      : '<span style="background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700">⏳ 대기</span>';
    html += '<tr class="rv-table-row' + (_curReviewIdx === i ? ' active-row' : '') + '" onclick="selectReview(' + i + ')" style="cursor:pointer">' +
      '<td>' + catBadge(p.category) + '</td>' +
      '<td class="sl-title">' + esc(p.title) + '</td>' +
      '<td>' + statusHtml + '</td>' +
    '</tr>';
  });
  html += '</tbody></table>';
  el.innerHTML = html;
}

function selectReview(idx) {
  _curReviewIdx = idx;
  var p = _reviewProposals[idx];
  document.getElementById('rv-split').style.display = 'flex';
  // 좌측: 제안 상세 + 첨부파일 미리보기
  var pdfHtml = '';
  var fileUrl = p.driveUrl || p.fileUrl || '';
  var fileName = p.pdf || p.fileName || '';
  if (fileUrl) {
    // Google Drive 미리보기
    var previewUrl = fileUrl.replace('/view', '/preview').replace('?usp=sharing', '');
    if (fileUrl.indexOf('drive.google.com') >= 0) {
      var fileId = fileUrl.match(/\/d\/([^\/]+)/) || fileUrl.match(/[?&]id=([^&]+)/);
      if (fileId) previewUrl = 'https://drive.google.com/file/d/' + fileId[1] + '/preview';
    }
    pdfHtml = '<div style="margin-top:16px;border-top:1px solid #e8edf5;padding-top:12px">' +
      '<div style="font-size:13px;font-weight:600;color:var(--navy);margin-bottom:8px">📎 첨부파일: ' + esc(fileName) + '</div>' +
      '<iframe src="' + previewUrl + '" style="width:100%;height:500px;border:1px solid #e8edf5;border-radius:8px" allowfullscreen></iframe>' +
      '<a href="' + esc(fileUrl) + '" target="_blank" style="display:inline-block;margin-top:6px;color:var(--blue);font-size:12px">🔗 새 탭에서 열기</a>' +
    '</div>';
  } else if (fileName) {
    pdfHtml = '<div style="margin-top:12px"><span style="color:#94a3b8;font-size:13px">📎 ' + esc(fileName) + ' (미리보기 불가)</span></div>';
  }
  document.getElementById('rv-detail-area').innerHTML =
    '<div style="margin-bottom:10px">' + catBadge(p.category) + '</div>' +
    '<h3 style="font-size:17px;font-weight:800;color:var(--navy);margin-bottom:12px">' + esc(p.title) + '</h3>' +
    '<div style="font-size:13px;color:#555;line-height:1.8">' + fmtSummary(p.summary) + '</div>' +
    pdfHtml;
  // 우측: 기존 검토의견 채우기
  var ex = p.existingReview;
  document.getElementById('rv-opinion').value = ex ? (ex.opinion || '') : '';
  document.getElementById('rv-reviewer').value = ex ? (ex.reviewer || '') : '';
  document.getElementById('rv-reviewer-dept').value = ex ? (ex.reviewDept || '') : '';
  // 목록 활성 표시 갱신
  document.querySelectorAll('#rv-review-list .rv-table-row').forEach(function(el, i) {
    el.classList.toggle('active-row', i === idx);
  });
  document.getElementById('rv-split').scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function saveReviewFromSplit() {
  if (_curReviewIdx < 0) return;
  var p = _reviewProposals[_curReviewIdx];
  var opinion = document.getElementById('rv-opinion').value.trim();
  var reviewer = document.getElementById('rv-reviewer').value.trim();
  var reviewDept = document.getElementById('rv-reviewer-dept').value.trim();
  if (!reviewer) return alert('검토자를 입력해주세요.');
  if (!opinion) return alert('검토의견을 입력해주세요.');
  if (SCRIPT_URL) {
    apiPost({
      action: 'saveReview', code: _rvCode,
      proposalId: p.id, proposalTitle: p.title,
      reviewer: reviewer, reviewDept: reviewDept, opinion: opinion
    }).then(function(res) {
      if (res.ok) {
        alert('✅ 검토의견이 저장되었습니다.');
        p.existingReview = { opinion: opinion, reviewer: reviewer, reviewDept: reviewDept };
        renderReviewListFromServer({ proposals: _reviewProposals });
        // 다음 미완료 제안으로 이동
        var next = _reviewProposals.findIndex(function(pp, i) { return i > _curReviewIdx && !pp.existingReview; });
        if (next >= 0) selectReview(next);
      } else alert('❌ 저장 실패: ' + (res.error || ''));
    });
  }
}

// ── 심사: 목록 + 분할화면 ──
var _judgeProposals = [];
var _curJudgeIdx = -1;

function renderJudgeListFromServer(data) {
  _judgeProposals = data.proposals || [];
  var el = document.getElementById('rv-judge-list');
  var done = _judgeProposals.filter(function(p) { return p.existingScore; }).length;
  var progEl = document.getElementById('jd-progress');
  if (progEl) progEl.textContent = done + '/' + _judgeProposals.length + '건 완료';
  if (!_judgeProposals.length) { el.innerHTML = '<p style="text-align:center;color:#aaa;padding:40px">배정된 제안이 없습니다.</p>'; return; }
  var html = '<div style="display:flex;flex-wrap:wrap;gap:6px">';
  _judgeProposals.forEach(function(p, i) {
    var isDone = p.existingScore;
    html += '<div class="rv-list-item' + (_curJudgeIdx === i ? ' active' : '') + '" onclick="selectJudge(' + i + ')">' +
      '<div class="rv-item-title">' + catBadge(p.category) + ' ' + esc(p.title) + '</div>' +
      '<div class="rv-item-status ' + (isDone ? 'rv-item-done' : 'rv-item-pending') + '">' + (isDone ? '✅ ' + p.existingScore.total + '점' : '⏳ 대기') + '</div>' +
    '</div>';
  });
  html += '</div>';
  el.innerHTML = html;
}

function selectJudge(idx) {
  _curJudgeIdx = idx;
  var p = _judgeProposals[idx];
  document.getElementById('jd-split').style.display = 'flex';
  // 좌측: 제안 상세
  document.getElementById('jd-detail-area').innerHTML =
    '<div style="margin-bottom:10px">' + catBadge(p.category) + '</div>' +
    '<h3 style="font-size:17px;font-weight:800;color:var(--navy);margin-bottom:12px">' + esc(p.title) + '</h3>' +
    '<div style="font-size:13px;color:#555;line-height:1.8">' + fmtSummary(p.summary) + '</div>';
  // 우측: 채점 폼
  var ex = p.existingScore;
  var html = '';
  SCORE_ITEMS.forEach(function(item) {
    html += '<div class="score-row"><div class="score-row-label">' + item.name + ' <span style="color:#aaa">(' + item.max + ')</span></div><select class="score-select" id="jds-' + item.key + '" onchange="calcSplitTotal()">';
    html += '<option value="">선택</option>';
    item.options.forEach(function(val, vi) {
      var sel = ex && Number(ex[item.key]) === val ? ' selected' : '';
      html += '<option value="' + val + '"' + sel + '>' + val + '점 - ' + item.labels[vi] + '</option>';
    });
    html += '</select></div>';
  });
  document.getElementById('jd-score-form').innerHTML = html;
  document.getElementById('jd-judge-name').value = '';
  calcSplitTotal();
  // 목록 활성 표시
  document.querySelectorAll('#rv-judge-list .rv-list-item').forEach(function(el, i) {
    el.classList.toggle('active', i === idx);
  });
  document.getElementById('jd-split').scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function calcSplitTotal() {
  var total = 0;
  SCORE_ITEMS.forEach(function(item) {
    var v = parseInt(document.getElementById('jds-' + item.key).value) || 0;
    total += v;
  });
  document.getElementById('jd-total-display').textContent = '합계: ' + total + '점';
}

function saveScoreFromSplit() {
  if (_curJudgeIdx < 0) return;
  var p = _judgeProposals[_curJudgeIdx];
  var judgeName = document.getElementById('jd-judge-name').value.trim();
  if (!judgeName) return alert('심사자를 입력해주세요.');
  var scores = {};
  var total = 0;
  var allFilled = true;
  SCORE_ITEMS.forEach(function(item) {
    var v = parseInt(document.getElementById('jds-' + item.key).value) || 0;
    if (!v) allFilled = false;
    scores[item.key] = v;
    total += v;
  });
  if (!allFilled) return alert('모든 항목을 채점해주세요.');
  if (SCRIPT_URL) {
    apiPost({
      action: 'saveScore', code: _rvCode,
      proposalId: p.id, proposalTitle: p.title,
      feasibility: scores.feasibility, creativity: scores.creativity,
      effectiveness: scores.effectiveness, efficiency: scores.efficiency,
      scope: scores.scope, duration: scores.duration, effort: scores.effort
    }).then(function(res) {
      if (res.ok) {
        alert('✅ 심사 점수가 저장되었습니다. (합계: ' + res.total + '점)');
        p.existingScore = { total: res.total };
        SCORE_ITEMS.forEach(function(item) { p.existingScore[item.key] = scores[item.key]; });
        renderJudgeListFromServer({ proposals: _judgeProposals });
        var next = _judgeProposals.findIndex(function(pp, i) { return i > _curJudgeIdx && !pp.existingScore; });
        if (next >= 0) selectJudge(next);
      } else alert('❌ 저장 실패: ' + (res.error || ''));
    });
  }
}

function renderJudgeList(cfg) {
  var items = DATA.filter(cfg.filter);
  var el = document.getElementById('rv-judge-list');
  if (!items.length) { el.innerHTML = '<p style="text-align:center;color:#aaa;padding:40px">배정된 제안이 없습니다.</p>'; return; }
  var html = '';
  items.forEach(function(d, idx) {
    html += '<div class="rv-card">' +
      '<div class="rv-card-head">' + catBadge(d.category) + ' <b>' + esc(d.title) + '</b></div>' +
      '<div class="rv-card-summary">' + fmtSummary(d.summary) + '</div>' +
      '<table class="score-table"><thead><tr><th>심사항목</th><th>배점</th>';
    SCORE_ITEMS[0].options.forEach(function() { html += '<th></th>'; });
    html += '<th>득점</th></tr></thead><tbody>';
    SCORE_ITEMS.forEach(function(item) {
      html += '<tr><td class="score-label">' + item.name + '<br><span class="score-max">(' + item.max + '점)</span></td>';
      html += '<td class="score-max-cell">' + item.max + '</td>';
      item.options.forEach(function(val, vi) {
        var rid = 'sc-' + idx + '-' + item.key + '-' + val;
        html += '<td class="score-opt"><label>' +
          '<input type="radio" name="sc-' + idx + '-' + item.key + '" value="' + val + '" onchange="calcJudgeTotal(' + idx + ')">' +
          '<span class="score-val">' + val + '</span>' +
          '<span class="score-desc">' + item.labels[vi] + '</span>' +
        '</label></td>';
      });
      html += '<td class="score-got" id="sc-got-' + idx + '-' + item.key + '">-</td></tr>';
    });
    html += '<tr class="score-total-row"><td colspan="' + (SCORE_ITEMS[0].options.length + 2) + '" style="text-align:right;font-weight:700">합 계</td>' +
      '<td class="score-got" id="sc-total-' + idx + '" style="font-size:18px;font-weight:800;color:var(--blue)">0</td></tr>';
    html += '</tbody></table>' +
      '<div style="text-align:right;margin-top:8px"><button class="btn-save" onclick="saveJudgeScore(' + idx + ')">채점 저장</button></div>' +
    '</div>';
  });
  el.innerHTML = html;
}

function calcJudgeTotal(idx) {
  var total = 0;
  SCORE_ITEMS.forEach(function(item) {
    var radios = document.getElementsByName('sc-' + idx + '-' + item.key);
    var gotEl = document.getElementById('sc-got-' + idx + '-' + item.key);
    for (var i = 0; i < radios.length; i++) {
      if (radios[i].checked) {
        var v = parseInt(radios[i].value);
        gotEl.textContent = v;
        total += v;
        break;
      }
    }
  });
  document.getElementById('sc-total-' + idx).textContent = total;
}

// ── 추진현황 탭 ─────────────────────────────────────────
var TRACK_DATA = [];
var _trackFilter = '전체';
var TRACK_STATUS = [
  {key:'협의중',   color:'#e9a825', icon:'💬'},
  {key:'추진중',   color:'#2a9d8f', icon:'🚀'},
  {key:'완료',     color:'#27ae60', icon:'✅'},
  {key:'보류',     color:'#95a5a6', icon:'⏸️'},
];

function loadTracking() {
  if (!SCRIPT_URL) return Promise.resolve();
  return api({action:'getTracking'}).then(function(rows) {
    TRACK_DATA = Array.isArray(rows) ? rows : [];
  }).catch(function() { TRACK_DATA = []; });
}

function renderTracking() {
  loadTracking().then(function() { renderTrackingView(); });
}

function renderTrackingView() {
  var adoptedList = DATA.filter(function(d) { return ADOPTED.has(d.award); });
  // 각 제안의 최신 상태 계산
  var proposalStatus = {};
  TRACK_DATA.forEach(function(t) {
    if (!proposalStatus[t.proposalId] || t.createdAt > proposalStatus[t.proposalId].createdAt) {
      proposalStatus[t.proposalId] = t;
    }
  });

  // 요약 카드
  var counts = {};
  TRACK_STATUS.forEach(function(s) { counts[s.key] = 0; });
  var noTracking = 0;
  adoptedList.forEach(function(d) {
    var ps = proposalStatus[d.id];
    if (ps && counts[ps.status] !== undefined) counts[ps.status]++;
    else noTracking++;
  });

  var summaryHtml = '<div class="tracking-summary">';
  TRACK_STATUS.forEach(function(s) {
    summaryHtml += '<div class="tracking-summary-card" style="border-left:4px solid ' + s.color + '">'
      + '<div class="tracking-summary-icon">' + s.icon + '</div>'
      + '<div class="tracking-summary-num">' + counts[s.key] + '</div>'
      + '<div class="tracking-summary-label">' + s.key + '</div>'
      + '</div>';
  });
  if (noTracking > 0) {
    summaryHtml += '<div class="tracking-summary-card" style="border-left:4px solid #ddd">'
      + '<div class="tracking-summary-icon">📋</div>'
      + '<div class="tracking-summary-num">' + noTracking + '</div>'
      + '<div class="tracking-summary-label">미등록</div>'
      + '</div>';
  }
  summaryHtml += '</div>';
  document.getElementById('trackingSummary').innerHTML = summaryHtml;

  // 필터 네비게이션
  var filters = ['전체'].concat(TRACK_STATUS.map(function(s) { return s.key; }));
  var navHtml = filters.map(function(f) {
    return '<button class="sub-nav-btn' + (_trackFilter === f ? ' on' : '') + '" onclick="filterTracking(\'' + f + '\')">'
      + (f === '전체' ? '📋 ' : (TRACK_STATUS.find(function(s){return s.key===f;})||{}).icon + ' ')
      + f + '</button>';
  }).join('');
  document.getElementById('trackingNav').innerHTML = navHtml;

  // 카드 목록
  var filtered = adoptedList.filter(function(d) {
    if (_trackFilter === '전체') return true;
    var ps = proposalStatus[d.id];
    if (!ps) return _trackFilter === '미등록';
    return ps.status === _trackFilter;
  });

  if (!filtered.length) {
    document.getElementById('trackingArea').innerHTML = '<div class="empty">해당 상태의 제안이 없습니다.</div>';
    return;
  }

  var cardsHtml = '';
  filtered.forEach(function(d) {
    var ps = proposalStatus[d.id];
    var st = ps ? TRACK_STATUS.find(function(s){return s.key===ps.status;}) : null;
    var statusHtml = st
      ? '<span class="tracking-status-badge" style="background:' + st.color + '">' + st.icon + ' ' + st.key + '</span>'
      : '<span class="tracking-status-badge" style="background:#ccc">📋 미등록</span>';
    var deptHtml = ps && ps.dept ? '<span class="tracking-dept">' + esc(ps.dept) + '</span>' : '';

    // 타임라인: 해당 제안의 모든 이력
    var history = TRACK_DATA.filter(function(t) { return t.proposalId === d.id; });
    history.sort(function(a, b) { return (b.date || b.createdAt || '').localeCompare(a.date || a.createdAt || ''); });

    var timelineHtml = '';
    if (history.length) {
      var showAll = history.length <= 3;
      var visibleItems = showAll ? history : history.slice(0, 3);
      timelineHtml = '<div class="timeline">';
      visibleItems.forEach(function(h) {
        var hst = TRACK_STATUS.find(function(s){return s.key===h.status;}) || {color:'#ccc',icon:'●'};
        timelineHtml += '<div class="timeline-item">'
          + '<div class="timeline-dot" style="background:' + hst.color + '"></div>'
          + '<div class="timeline-content">'
          + '<div class="timeline-date">' + esc(h.date || '') + ' <span class="timeline-writer">' + esc(h.writer || '') + (h.dept ? ' · ' + esc(h.dept) : '') + '</span></div>'
          + '<div class="timeline-text">' + esc(h.content || '') + '</div>'
          + '</div></div>';
      });
      timelineHtml += '</div>';
      if (!showAll) {
        timelineHtml += '<button class="timeline-more" onclick="toggleTimeline(\'' + d.id + '\',this)">+ ' + (history.length - 3) + '건 더보기</button>';
        timelineHtml += '<div class="timeline timeline-hidden" id="tl-more-' + d.id + '">';
        history.slice(3).forEach(function(h) {
          var hst2 = TRACK_STATUS.find(function(s){return s.key===h.status;}) || {color:'#ccc',icon:'●'};
          timelineHtml += '<div class="timeline-item">'
            + '<div class="timeline-dot" style="background:' + hst2.color + '"></div>'
            + '<div class="timeline-content">'
            + '<div class="timeline-date">' + esc(h.date || '') + ' <span class="timeline-writer">' + esc(h.writer || '') + (h.dept ? ' · ' + esc(h.dept) : '') + '</span></div>'
            + '<div class="timeline-text">' + esc(h.content || '') + '</div>'
            + '</div></div>';
        });
        timelineHtml += '</div>';
      }
    } else {
      timelineHtml = '<div style="color:#aaa;font-size:13px;padding:8px 0">아직 등록된 이력이 없습니다.</div>';
    }

    cardsHtml += '<div class="tracking-card">'
      + '<div class="tracking-card-hdr">'
      + '<div class="tracking-card-award">' + awardBadge(d.award) + '</div>'
      + '<div class="tracking-card-title">' + esc(d.title) + '</div>'
      + '<div class="tracking-card-meta">' + statusHtml + deptHtml + '</div>'
      + '</div>'
      + '<div class="tracking-card-body">'
      + timelineHtml
      + '</div></div>';
  });
  document.getElementById('trackingArea').innerHTML = cardsHtml;
}

function filterTracking(key) {
  _trackFilter = key;
  document.querySelectorAll('#trackingNav .sub-nav-btn').forEach(function(btn, i) {
    var filters = ['전체'].concat(TRACK_STATUS.map(function(s){return s.key;}));
    btn.classList.toggle('on', filters[i] === key);
  });
  renderTrackingView();
}

function toggleTimeline(proposalId, btn) {
  var el = document.getElementById('tl-more-' + proposalId);
  if (!el) return;
  var hidden = el.classList.contains('timeline-hidden');
  el.classList.toggle('timeline-hidden');
  btn.textContent = hidden ? '접기' : btn.textContent;
  if (hidden) btn.style.display = 'none';
}

// ── 추진현황 관리 (관리자) ──
function initMgTracking() {
  var sel = document.getElementById('tk-proposal');
  if (!sel) return;
  var adoptedList = DATA.filter(function(d) { return ADOPTED.has(d.award); });
  sel.innerHTML = '<option value="">제안을 선택하세요</option>';
  adoptedList.forEach(function(d) {
    sel.innerHTML += '<option value="' + d.id + '">' + d.award + ' | ' + esc(d.title) + '</option>';
  });
  document.getElementById('tk-form').style.display = 'none';
  document.getElementById('tk-existing').innerHTML = '';
  // 오늘 날짜 기본값
  var today = new Date().toISOString().split('T')[0];
  var dateEl = document.getElementById('tk-date');
  if (dateEl) dateEl.value = today;
}

function onTrackingProposalSelect() {
  var proposalId = document.getElementById('tk-proposal').value;
  if (!proposalId) {
    document.getElementById('tk-form').style.display = 'none';
    document.getElementById('tk-existing').innerHTML = '';
    return;
  }
  document.getElementById('tk-form').style.display = 'block';
  // 기존 이력 표시
  var history = TRACK_DATA.filter(function(t) { return t.proposalId === proposalId; });
  history.sort(function(a, b) { return (b.date || b.createdAt || '').localeCompare(a.date || a.createdAt || ''); });
  if (!history.length) {
    document.getElementById('tk-existing').innerHTML = '<div style="color:#aaa;font-size:13px;padding:8px 0">이 제안에 등록된 이력이 없습니다.</div>';
    return;
  }
  var html = '<div style="font-weight:700;color:var(--navy);font-size:14px;margin-bottom:8px">기존 이력</div><div class="timeline">';
  history.forEach(function(h) {
    var hst = TRACK_STATUS.find(function(s){return s.key===h.status;}) || {color:'#ccc'};
    html += '<div class="timeline-item">'
      + '<div class="timeline-dot" style="background:' + hst.color + '"></div>'
      + '<div class="timeline-content">'
      + '<div class="timeline-date">' + esc(h.date || '') + ' <span class="timeline-writer">' + esc(h.writer || '') + (h.dept ? ' · ' + esc(h.dept) : '') + '</span>'
      + (isAdmin ? ' <button style="border:none;background:none;color:var(--rose);cursor:pointer;font-size:11px" onclick="deleteTrackingEntry(\'' + h.id + '\')">삭제</button>' : '')
      + '</div>'
      + '<div class="timeline-text">' + esc(h.content || '') + '</div>'
      + '</div></div>';
  });
  html += '</div>';
  document.getElementById('tk-existing').innerHTML = html;
}

function saveTrackingEntry() {
  var proposalId = document.getElementById('tk-proposal').value;
  if (!proposalId) return showToast('제안을 선택하세요', 'err');
  var content = document.getElementById('tk-content').value.trim();
  if (!content) return showToast('협의 내용을 입력하세요', 'err');
  apiPost({
    action: 'saveTracking', pw: ADMIN_PW,
    proposalId: proposalId,
    status: document.getElementById('tk-status').value,
    dept: document.getElementById('tk-dept').value.trim(),
    date: document.getElementById('tk-date').value,
    content: content,
    writer: document.getElementById('tk-writer').value.trim()
  }).then(function(res) {
    if (res.ok) {
      showToast('추진현황이 저장되었습니다', 'ok');
      document.getElementById('tk-content').value = '';
      loadTracking().then(function() { onTrackingProposalSelect(); });
    } else showToast('저장 실패: ' + (res.error || ''), 'err');
  }).catch(function() { showToast('서버 오류', 'err'); });
}

function deleteTrackingEntry(id) {
  if (!confirm('이 이력을 삭제하시겠습니까?')) return;
  apiPost({ action: 'deleteTracking', pw: ADMIN_PW, id: id }).then(function(res) {
    if (res.ok) {
      showToast('삭제되었습니다', 'ok');
      loadTracking().then(function() { onTrackingProposalSelect(); });
    } else showToast('삭제 실패', 'err');
  });
}

// 검토자 패널에서 추진현황 저장
function saveTrackingFromReview() {
  if (_curReviewIdx < 0) return;
  var p = _reviewProposals[_curReviewIdx];
  var content = document.getElementById('rv-tk-content').value.trim();
  if (!content) return alert('협의 내용을 입력하세요.');
  var reviewer = document.getElementById('rv-reviewer').value.trim();
  var reviewDept = document.getElementById('rv-reviewer-dept').value.trim();
  apiPost({
    action: 'saveTracking', code: _rvCode,
    proposalId: p.id,
    status: document.getElementById('rv-tk-status').value,
    dept: reviewDept,
    date: document.getElementById('rv-tk-date').value,
    content: content,
    writer: reviewer
  }).then(function(res) {
    if (res.ok) {
      alert('추진현황이 저장되었습니다.');
      document.getElementById('rv-tk-content').value = '';
    } else alert('저장 실패: ' + (res.error || ''));
  }).catch(function() { alert('서버 오류'); });
}

function saveJudgeScore(idx) {
  var total = parseInt(document.getElementById('sc-total-' + idx).textContent);
  if (!total || total === 0) return alert('채점을 완료해주세요.');

  if (SCRIPT_URL && _judgeProposals && _judgeProposals[idx]) {
    var p = _judgeProposals[idx];
    var scores = {};
    SCORE_ITEMS.forEach(function(item) {
      var radios = document.getElementsByName('sc-' + idx + '-' + item.key);
      for (var i = 0; i < radios.length; i++) {
        if (radios[i].checked) { scores[item.key] = parseInt(radios[i].value); break; }
      }
    });
    var btn = event.target;
    if (btn) { btn.disabled = true; btn.textContent = '저장 중...'; }
    apiPost({
      action: 'saveScore', code: _rvCode,
      proposalId: p.id, proposalTitle: p.title,
      feasibility: scores.feasibility || 0, creativity: scores.creativity || 0,
      effectiveness: scores.effectiveness || 0, efficiency: scores.efficiency || 0,
      scope: scores.scope || 0, duration: scores.duration || 0, effort: scores.effort || 0
    }).then(function(res) {
      if (btn) { btn.disabled = false; btn.textContent = '채점 저장'; }
      if (res.ok) alert('✅ 심사 점수가 저장되었습니다. (합계: ' + res.total + '점)' + (res.updated ? ' [수정됨]' : ''));
      else alert('❌ 저장 실패: ' + (res.error || ''));
    }).catch(function() {
      if (btn) { btn.disabled = false; btn.textContent = '채점 저장'; }
      alert('❌ 서버 오류');
    });
    return;
  }
  alert('✅ 심사 점수가 저장되었습니다. (합계: ' + total + '점)');
}
